function _chart(tiles,d3,width,tile_data,path,tippy,state_codes)
{
  const height = 500;
  console.log(tiles.features);
  const viewportWidth = 900;
  const svg = d3
    .create('svg')
    .attr("viewBox", [0, 0, viewportWidth, 500])
    .attr('width', width)
    .attr('height', height);

  //This translation centers the svg
  var g = svg
    .append('g')
    .attr('transform', 'translate(-240,' + (height - 30) + ')');

  //Add a tooltip
  //const tooltip = g.append("g").attr("id", "tooltip").style("fill", 'black');
  
  //select all from tile data, tiles doesn't match anything so it creates the elements
  g.selectAll('svg_tiles')
    .data(tile_data)
    //The enter selection is typically used to create “missing” elements corresponding to new data. 
    .enter()
    //creats element path
    .append('path')
    .attr('d', path)
    .style("fill", 'white')
    .style("stroke", 'black')
    .attr('title', d => d.properties.name)
    .on("mouseover", function() {
      // use back-ticks for string templates with variables
      //tippy is a tool tip module created below
      tippy(this, {content: `${this.getAttribute('title')}`});
    })
  //Adding state label
  g.selectAll("state_labels")
    .data(tile_data)
    .enter()
    .append("g")
    .attr("transform", d => {
      const center = path.centroid(d);
      return `translate(${center[0]}, ${center[1] + 5})`; // unclear why I need to +5....
    })
    .append("text")
    .style("pointer-events", "none")
    //gets the 2 letter abbr.
    .text(
      d =>
        state_codes.find(
          st => st.State.toLowerCase() === d.properties.name.toLowerCase()
        ).Code
    )
    .style("text-anchor", "middle")
    .style("font-size", 15 + "px")
    .style("font-family", "sans-serif");

  return svg.node();
}


