async function _tg(FileAttachment){return(
await FileAttachment("tiles.topo.json").json()
)}

function _tiles(topojson,tg){return(
topojson.feature(tg, tg.objects.tiles)
)}

function _tile_data(tiles){return(
tiles.features
)}

function _path(d3,transform){return(
d3.geoPath().projection(transform)
)}

function _transform(d3){return(
d3.geoTransform({
  point: function(x, y) {
    this.stream.point(x / 1.5, -y / 1.5); // added here
  }
})
)}

